module alu(
    input [31:0] a, b,
    input [5:0] aluc,
    output [31:0] r,
    output zero, carry, negative, overflow, flag
);
    parameter ADD = 6'b100000;
    parameter ADDU = 6'b100001;
    parameter SUB = 6'b100010;
    parameter SUBU = 6'b100011;
    parameter AND = 6'b100100;
    parameter OR = 6'b100101;
    parameter XOR = 6'b100110;
    parameter NOR = 6'b100111;
    parameter SLT = 6'b101010;
    parameter SLTU = 6'b101011;
    parameter SLL = 6'b000000;
    parameter SRL = 6'b000010;
    parameter SRA = 6'b000011;
    parameter SLLV = 6'b000100;
    parameter SRLV = 6'b000110;
    parameter SRAV = 6'b000111;
    parameter LUI = 6'b001111;

    wire [31:0] a_signed, b_signed;
    wire [31:0] res;
    assign a_signed = $signed(a);
    assign b_signed = $signed(b);
    assign r = res;
    assign flag = (aluc == SLT || aluc == SLTU) ? res[0] : 1'bz;
    assign zero = ~|res ? 1 : 0;
    reg carry_reg;
    reg negative_reg;
    reg overflow_reg;
    always @(*) begin
        case (aluc)
            ADD: {carry_reg, res} = a_signed + b_signed;
            ADDU: {carry_reg, res} = a + b;
            SUB: {carry_reg, res} = a_signed - b_signed;
            SUBU: {carry_reg, res} = a - b;
            AND: res = a & b;
            OR: res = a | b;
            XOR: res = a ^ b;
            NOR: res = ~(a | b);
            SLT: res = a_signed < b_signed ? 32'b1 : 32'b0;
            SLTU: res = a < b ? 32'b1 : 32'b0;
            SLL: res = b << a[4:0];
            SRL: res = b >> a[4:0];
            SRA: res = b >>> a[4:0];
            SLLV: res = b << a[4:0];
            SRLV: res = b >> a[4:0];
            SRAV: res = b >>> a[4:0];
            LUI: res = {b[15:0], 16'b0};
            default: res = 32'bz;

        negative_reg = res[31];
        overflow_reg = (aluc == ADD || aluc == SUB) ? ((a[31] == b[31]) && (res[31] != a[31])) : 1'bz;
    endcase

    end // Auto-repaired
    assign carry = (aluc == ADD || aluc == SUB) ? carry_reg : 1'bz;
    assign negative = negative_reg;
    assign overflow = overflow_reg;
endmodule
